            vputils::isSingleScalar(RepR->getOperand(1))) {
          // Stores to invariant addresses need to store the last lane only.
          // Clone for the last lane and redirect all users to the cloned def
          // before erasing the original recipe.
          VPValue *LastLaneDef =
              cloneForLane(Plan, Builder, IdxTy, RepR,
                           VPLane::getLastLaneForVF(VF), Def2LaneDefs);
          Def2LaneDefs[RepR] = {LastLaneDef};
          RepR->replaceAllUsesWith(LastLaneDef);
          ToRemove.push_back(RepR);
        } else {
          // Create single-scalar version of RepR for all lanes.
